const currentMonth = 3; // March
function isSlotInWindow(slot) {
  if (!slot || slot.time_zone !== 'utc' || slot.status !== 'available') return false;
  const start = new Date(slot.start_time);
  if (isNaN(start.getTime())) return false;
  const year = start.getUTCFullYear();
  const month = start.getUTCMonth() + 1;
  const dow = start.getUTCDay(); // 0=Sun ... 3=Wed
  if (year !== currentYear || month !== currentMonth || dow !== 3) return false;
  if (slot.duration_minutes !== 30 || slot.is_morning_slot !== true) return false;
  const hour = start.getUTCHours();
  const minute = start.getUTCMinutes();
