  cp2Passed = correctTimeBookings.some(function(pair) {
    return pair.slot && pair.slot.id === earliestSlot.id;
  });
}
checkpoints.push({ passed: cp2Passed, weight: 0.35 });
// CP3 (0.25): Booking includes full contact info and the 'new_product_design' topic
const cp3Passed = correctTimeBookings.some(function(pair) {
  const booking = pair.booking;
  if (!booking) return false;
  if (!booking.name || !booking.email || !booking.company) return false;
